    std::string constraint_name;
    double impact;
    std::string description;
};

class MmsSolver {
public:
    json solve(const json& input) {
        CpModelBuilder model;
        std::string request_id = input["request_id"];

        auto trains = input["trains"];
        auto routes = input["routes"];
        auto config = input["config"];

        // Decision variables: assign[t][r] = 1 if train t assigned to route r
        std::vector<std::vector<BoolVar>> assign;
        assign.resize(trains.size());

        for (size_t t = 0; t < trains.size(); t++) {
            assign[t].resize(routes.size());
            for (size_t r = 0; r < routes.size(); r++) {
                assign[t][r] = model.NewBoolVar();
            }
        }

        // Hard constraint: Each train assigned to at most one route
        for (size_t t = 0; t < trains.size(); t++) {
            std::vector<BoolVar> train_routes;
            for (size_t r = 0; r < routes.size(); r++) {
                train_routes.push_back(assign[t][r]);
            }
            model.AddAtMostOne(train_routes);
        }

        // Hard constraint: Route requirements (exactly N trains)
        for (size_t r = 0; r < routes.size(); r++) {
            std::vector<BoolVar> route_trains;
            for (size_t t = 0; t < trains.size(); t++) {
                // Check fleet compatibility
                if (isFleetAllowed(trains[t], routes[r])) {
                    route_trains.push_back(assign[t][r]);
                }
            }

            int required = routes[r]["required_trains"];
            model.AddEquality(LinearExpr::Sum(route_trains), required);
        }

        // Hard constraint: Fitness status
        for (size_t t = 0; t < trains.size(); t++) {
            if (trains[t]["fitness_status"] != "FIT") {
                for (size_t r = 0; r < routes.size(); r++) {
                    model.AddEquality(assign[t][r], 0);
                }
            }
        }

        // Hard constraints from input
        for (const auto& constraint : input["hard_constraints"]) {
            size_t train_idx = findTrainIndex(trains, constraint["train_id"]);
            if (train_idx < trains.size()) {
                for (size_t r = 0; r < routes.size(); r++) {
                    model.AddEquality(assign[train_idx][r], 0);
                }
            }
        }

        // NEW v2.1: Hard constraint - Unavailability events
        if (input.contains("unavailability_events")) {
            for (const auto& event : input["unavailability_events"]) {
                if (event["status"] == "ACTIVE" && event["blocks_run_assignment"].get<bool>()) {
                    size_t train_idx = findTrainIndex(trains, event["train_id"]);
                    if (train_idx < trains.size()) {
                        for (size_t r = 0; r < routes.size(); r++) {
                            model.AddEquality(assign[train_idx][r], 0);
                        }
                    }
                }
            }
        }

        // NEW v2.1: Hard constraint - Route compatibility
        if (input.contains("route_compatibility")) {
            for (const auto& compat : input["route_compatibility"]) {
                if (!compat["is_compatible"].get<bool>()) {
                    size_t train_idx = findTrainIndex(trains, compat["train_id"]);
                    size_t route_idx = findRouteIndex(routes, compat["route_id"]);
                    if (train_idx < trains.size() && route_idx < routes.size()) {
                        model.AddEquality(assign[train_idx][route_idx], 0);
                    }
                }
            }
        }

        // Soft constraint: Mileage balance
        std::vector<IntVar> mileage_penalties;
        auto penalties = config["soft_constraint_penalties"];
        int mileage_weight = penalties["mileage_imbalance"].get<int>();

        for (size_t t = 0; t < trains.size(); t++) {
            int current = trains[t]["current_mileage"];
            int target = trains[t]["target_mileage"];
            int variance = std::abs(current - target);

            for (size_t r = 0; r < routes.size(); r++) {
                int route_km = routes[r]["expected_km"];

                // Penalty for assigning over-utilized train to high-km route
                if (current > target && route_km > 200) {
                    IntVar penalty = model.NewIntVar({0, variance * mileage_weight});
                    model.AddEquality(penalty, variance * mileage_weight)
                        .OnlyEnforceIf(assign[t][r]);
                    model.AddEquality(penalty, 0)
                        .OnlyEnforceIf(assign[t][r].Not());
                    mileage_penalties.push_back(penalty);
                }
            }
        }

        // Objective: Minimize total penalty
        model.Minimize(LinearExpr::Sum(mileage_penalties));

        // Solve
        SatParameters params;
        params.set_max_time_in_seconds(
            config["max_solve_time_seconds"].get<double>()
        );
        params.set_num_search_workers(
            config["num_workers"].get<int>()
        );

        Model cp_model;
        cp_model.Add(NewSatParameters(params));

        // Progress callback
        int callback_count = 0;
        cp_model.Add(NewFeasibleSolutionObserver([&](const CpSolverResponse& r) {
            callback_count++;
            if (callback_count % 5 == 0) {
                emitProgress(request_id, 
                    std::min(90.0, callback_count * 3.0),
                    r.objective_value(), true);
            }
        }));

        CpSolverResponse response = SolveCpModel(model.Build(), &cp_model);

        // Build result
        json result;
        result["type"] = "RESULT";
        result["request_id"] = request_id;
        result["solve_time_ms"] = response.wall_time() * 1000;

        if (response.status() == CpSolverStatus::OPTIMAL ||
            response.status() == CpSolverStatus::FEASIBLE) {

            result["status"] = response.status() == CpSolverStatus::OPTIMAL 
                ? "OPTIMAL" : "FEASIBLE";

            json assignments = json::array();

            for (size_t t = 0; t < trains.size(); t++) {
                for (size_t r = 0; r < routes.size(); r++) {
                    if (SolutionBooleanValue(response, assign[t][r])) {
